{"files":[{"path":"src/router.ts","content":"import type { RouteParams, RouteRecordRaw } from 'vue-router'
import { createRouter, createWebHashHistory } from 'vue-router'
import { isAuthorized } from './store/user'

export type AppRouteNames
  = | 'global-feed'
    | 'my-feed'
    | 'tag'
    | 'article'
    | 'create-article'
    | 'edit-article'
    | 'login'
    | 'register'
    | 'profile'
    | 'profile-favorites'
    | 'settings'
    | 'not-found'

export const routes: RouteRecordRaw[] = [
  {
    name: 'global-feed',
    path: '/',
    component: () => import('./pages/Home.vue'),
  },
  {
    name: 'my-feed',
    path: '/my-feeds',
    component: () => import('./pages/Home.vue'),
    beforeEnter: () => isAuthorized() ? true : { name: 'login' as const },
  },
  {
    name: 'tag',
    path: '/tag/:tag',
    component: () => import('./pages/Home.vue'),
  },
  {
    name: 'article',
    path: '/article/:slug',
    component: () => import('./pages/Article.vue'),
  },
  {
    name: 'edit-article',
    path: '/article/:slug/edit',
    component: () => import('./pages/EditArticle.vue'),
    beforeEnter: () => isAuthorized() ? true : { name: 'login' as const },
  },
  {
    name: 'create-article',
    path: '/article/create',
    component: () => import('./pages/EditArticle.vue'),
    beforeEnter: () => isAuthorized() ? true : { name: 'login' as const },
  },
  {
    name: 'login',
    path: '/login',
    component: () => import('./pages/Login.vue'),
    beforeEnter: () => isAuthorized() ? { name: 'global-feed' as const } : true,
  },
  {
    name: 'register',
    path: '/register',
    component: () => import('./pages/Register.vue'),
    beforeEnter: () => isAuthorized() ? { name: 'global-feed' as const } : true,
  },
  {
    name: 'profile',
    path: '/profile/:username',
    component: () => import('./pages/Profile.vue'),
  },
  {
    name: 'profile-favorites',
    path: '/profile/:username/favorites',
    component: () => import('./pages/Profile.vue'),
  },
  {
    name: 'settings',
    path: '/settings',
    component: () => import('./pages/Settings.vue'),
    beforeEnter: () => isAuthorized() ? true : { name: 'login' as const },
  },
  {
    name: 'not-found',
    path: '/:pathMatch(.*)*',
    component: () => import('./pages/NotFound.vue'),
  },
]
export const router = createRouter({
  history: createWebHashHistory(),
  routes,
})

export async function routerPush(name: AppRouteNames, params?: RouteParams): ReturnType<typeof router.push> {
  return params === undefined
    ? await router.push({ name })
    : await router.push({ name, params })
}
"}],"summary":"Added route guards to my-feed, edit-article, create-article, and settings routes to redirect unauthenticated users to login.","uncertainty":[]}

